package resultscache

import (
	"fmt"

	"github.com/gogo/protobuf/types"
)

// AnyAdapter bridges the gogo-generated types.Any to wiresmith-generated
// code: wiresmith cannot embed message types generated by another protobuf
// runtime, so Extent.Response is declared google.protobuf.Any on the wire
// but carries this adapter in Go. Wire format is identical.
type AnyAdapter types.Any

// Any returns the gogo representation. A zero adapter yields nil, matching
// the previous *types.Any field shape where absent meant nil.
func (a *AnyAdapter) Any() *types.Any {
	if a == nil || (a.TypeUrl == "" && len(a.Value) == 0) {
		return nil
	}
	return (*types.Any)(a)
}

// FromAny converts a gogo Any (possibly nil) into the adapter representation.
func FromAny(v *types.Any) AnyAdapter {
	if v == nil {
		return AnyAdapter{}
	}
	return AnyAdapter(*v)
}

// SizeWiresmith implements the wiresmith customtype contract.
func (a *AnyAdapter) SizeWiresmith() int { return (*types.Any)(a).Size() }

// MarshalWiresmith implements the wiresmith customtype contract.
func (a *AnyAdapter) MarshalWiresmith(buf []byte) (int, error) {
	return (*types.Any)(a).MarshalTo(buf)
}

// UnmarshalWiresmith implements the wiresmith customtype contract.
func (a *AnyAdapter) UnmarshalWiresmith(buf []byte) error { return (*types.Any)(a).Unmarshal(buf) }

// EqualWiresmith implements the wiresmith customtype contract.
func (a *AnyAdapter) EqualWiresmith(other any) bool {
	o, ok := coerceAnyAdapter(other)
	if !ok {
		return false
	}
	return (*types.Any)(a).Equal((*types.Any)(o))
}

// CompareWiresmith implements the wiresmith customtype contract.
func (a *AnyAdapter) CompareWiresmith(other any) int {
	o, ok := coerceAnyAdapter(other)
	if !ok {
		return -1
	}
	return (*types.Any)(a).Compare((*types.Any)(o))
}

func coerceAnyAdapter(other any) (*AnyAdapter, bool) {
	switch o := other.(type) {
	case AnyAdapter:
		return &o, true
	case *AnyAdapter:
		return o, o != nil
	default:
		return nil, false
	}
}

// GoString implements fmt.GoStringer; gogoslick-generated code in
// pkg/querier/queryrange embeds these types by value and calls GoString,
// which wiresmith does not emit.
func (m *CachingOptions) GoString() string {
	type plain CachingOptions
	return fmt.Sprintf("%#v", (*plain)(m))
}

// GoString implements fmt.GoStringer (see CachingOptions.GoString).
func (e *Extent) GoString() string {
	type plain Extent
	return fmt.Sprintf("%#v", (*plain)(e))
}
